// Solution
function calculator<T extends number | { value: number }>(a: T, b: T): T {
    if (typeof a === 'object' && typeof b === 'object') {
        return a.value - b.value;
    } else {
        return a + b;
    }
}

solutions.python:
from typing import Any
class Calculator:
    def calculate(self, a: Any, b: Any) -> Any:
        if isinstance(a, dict) and isinstance(b, dict):
            return a['value'] - b['value'];
        elif isinstance(a, int) and isinstance(b, int):
            return a - b;
        else:
            return a + b;
